export const internalFunctions = {
  max: (...args) => {
    if (!args.length) throw new Error("max() requires arguments");
    return Math.max(...args);
  },

  min: (...args) => {
    if (!args.length) throw new Error("min() requires arguments");
    return Math.min(...args);
  },

  abs: (x) => Math.abs(x),

  round: (x) => Math.round(x),

  floor: (x) => Math.floor(x),

  ceil: (x) => Math.ceil(x),

  sqrt: (x) => {
    if (x < 0) throw new Error("sqrt() domain error");
    return Math.sqrt(x);
  },

  pow: (a, b) => a ** b,

  /* ================= TRIGONOMETRY ================= */

  sin: (x) => Math.sin(x),
  cos: (x) => Math.cos(x),
  tan: (x) => Math.tan(x),

  asin: (x) => Math.asin(x),
  acos: (x) => Math.acos(x),
  atan: (x) => Math.atan(x),

  /* ================= LOG / EXP ================= */

  log: (x) => {
    if (x <= 0) throw new Error("log() domain error");
    return Math.log(x);
  },

  log10: (x) => {
    if (x <= 0) throw new Error("log10() domain error");
    return Math.log10(x);
  },

  exp: (x) => Math.exp(x),

  /* ================= RANDOM ================= */

  random: () => Math.random(),

  /* ================= BOOLEAN / LOGIC ================= */

  and: (a, b) => Boolean(a && b),

  or: (a, b) => Boolean(a || b),

  not: (a) => !a,
  "!": (a) => !a,

  /* ================= COMPARISON ================= */

  eq: (a, b) => a === b,

  neq: (a, b) => a !== b,
  "notEqual": (a, b) => a !== b,

  gt: (a, b) => a > b,
  "greaterThan": (a, b) => a > b,

  lt: (a, b) => a < b,
  "lessThan": (a, b) => a < b,

  gte: (a, b) => a >= b,
  "greaterThanOrEqual": (a, b) => a >= b,

  lte: (a, b) => a <= b,
  "lessThanOrEqual": (a, b) => a <= b,

  /* ================= UTILITY ================= */

  clamp: (x, min, max) => {
    if (min > max) throw new Error("clamp(): min > max");
    return Math.min(Math.max(x, min), max);
  },

  if: (condition, a, b) => (condition ? a : b),

  /* ================= TYPE ================= */

  typeof: (x) => typeof x,

  /* ================= STRING ================= */

  length: (x) => {
    if (typeof x === "string" || Array.isArray(x)) {
      return x.length;
    }
    throw new Error("length() expects string or array");
  }
};